mkdirSync(resolve(evidenceRoot, 'datasets'), { recursive: true });
cpSync(resolve(root, 'evals/effectiveness/datasets/m12-mini.jsonl'), resolve(evidenceRoot, 'datasets/m12-mini.jsonl'));
writeFileSync(resolve(evidenceRoot, 'plugin-commit.txt'), `${execFileSync('git', ['rev-parse', 'HEAD'], { encoding: 'utf8' })}`);
writeFileSync(resolve(evidenceRoot, 'git-status.txt'), execFileSync('git', ['status', '--short'], { encoding: 'utf8' }));

const baseline = JSON.parse(readFileSync(resolve(root, 'evals/effectiveness/reports/test-coverage-001/baseline-result.json'), 'utf8'));
const treatment = JSON.parse(readFileSync(resolve(root, 'evals/effectiveness/reports/test-coverage-001/treatment-result.json'), 'utf8'));
const gate = JSON.parse(readFileSync(resolve(root, 'evals/effectiveness/reports/m12-release-gate.json'), 'utf8'));
const validationLogs = (treatment.validation_logs ?? []).map((p) => readFileSync(resolve(root, p), 'utf8')).join('\n');
const summary = {
  case_id: 'test-coverage-001',
  baseline_real_run_executed: baseline.real_run_executed === true,
  treatment_real_run_executed: treatment.real_run_executed === true,
  treatment_status: treatment.status,
  coverage_contract_passed: /Invoice coverage contract satisfied\./.test(validationLogs),
  final_eval_verdict: treatment.final_eval_verdict ?? treatment.evaluator_verdict ?? '',
  final_report_present: Boolean(treatment.final_report_path),
  validation_passed: treatment.validation_passed === true,
  secret_leak_detected: treatment.secret_leak_detected === true || baseline.secret_leak_detected === true,
  danger_full_access_used: treatment.danger_full_access_used === true || baseline.danger_full_access_used === true,
  m12_gate_status: gate.status,
  production_ready: false
};
writeFileSync(resolve(root, 'evals/effectiveness/reports/test-coverage-001/canary-pass-summary.json'), `${JSON.stringify(summary, null, 2)}\n`);
writeFileSync(resolve(root, 'evals/effectiveness/reports/test-coverage-001/CanaryPassSummary.md'), `# M12 test-coverage-001 Canary PASS Summary\n\nStatus: PASS\n\ntest-coverage-001 now has real baseline and real SDK-Orchestrated treatment evidence. The treatment completed through the direct evaluator PASS path:\n\nPlanner -> Dev Worker -> Evaluator PASS -> FinalReport\n\n## Evidence\n\n- Baseline real run executed: ${summary.baseline_real_run_executed}\n- Treatment real run executed: ${summary.treatment_real_run_executed}\n- Treatment status: ${summary.treatment_status}\n- Coverage contract passed: ${summary.coverage_contract_passed}\n- Final evaluator verdict: ${summary.final_eval_verdict}\n- FinalReport present: ${summary.final_report_present}\n- Validation passed: ${summary.validation_passed}\n- Secret leak detected: ${summary.secret_leak_detected}\n- Danger full access used: ${summary.danger_full_access_used}\n- M12 gate status: ${summary.m12_gate_status}\n- Production ready: ${summary.production_ready}\n\n## Scope\n\nThis freezes the test-coverage-001 single-case canary only. It does not make the project production ready and does not approve the full M12-mini dataset.\n`);
cpSync(resolve(root, 'evals/effectiveness/reports/test-coverage-001/CanaryPassSummary.md'), resolve(evidenceRoot, 'reports/CanaryPassSummary.md'));
cpSync(resolve(root, 'evals/effectiveness/reports/test-coverage-001/canary-pass-summary.json'), resolve(evidenceRoot, 'reports/canary-pass-summary.json'));

function walk(dir) {
  return readdirSync(dir).flatMap((entry) => {
    const path = resolve(dir, entry);
    const stat = statSync(path);
    if (stat.isDirectory()) return walk(path);
    return [path];
  });
}
const lines = walk(evidenceRoot)
  .filter((path) => !path.endsWith('/CHECKSUMS.sha256'))
  .sort()
  .map((path) => `${createHash('sha256').update(readFileSync(path)).digest('hex')}  ${path.slice(evidenceRoot.length + 1)}`);
writeFileSync(resolve(evidenceRoot, 'CHECKSUMS.sha256'), `${lines.join('\n')}\n`);
console.log(JSON.stringify({ evidenceRoot, files: lines.length, summary }, null, 2));
