  const headings = text.split(/\r?\n/).filter((line) => /^#{1,3}\s+/.test(line)).slice(0, 8).map(scrub);
  const lower = text.toLowerCase();
  return {
    file: f,
    bytes: Buffer.byteLength(text),
    headings,
    mentions_untrusted: lower.includes('untrusted'),
    mentions_ignored: lower.includes('ignored'),
